// shadcn
import { Card, CardContent } from "@/components/ui/card";
import {
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselNext,
  CarouselPrevious,
} from "@/components/ui/carousel";

// constants
const items = [
  {
    id: 1,
    image: "https://cdn.uiable.com/block/g1.jpg",
    title: "Project Details",
    description: "At half-past eight the door opened, the policeman appeared.",
  },
  {
    id: 2,
    image: "https://cdn.uiable.com/block/g2.jpg",
    title: "Project Details",
    description: "At half-past eight the door opened, the policeman appeared.",
  },
  {
    id: 3,
    image: "https://cdn.uiable.com/block/g3.jpg",
    title: "Project Details",
    description: "At half-past eight the door opened, the policeman appeared.",
  },
  {
    id: 4,
    image: "https://cdn.uiable.com/block/g4.jpg",
    title: "Project Details",
    description: "At half-past eight the door opened, the policeman appeared.",
  },
  {
    id: 5,
    image: "https://cdn.uiable.com/block/g5.jpg",
    title: "Project Details",
    description: "At half-past eight the door opened, the policeman appeared.",
  },
];

//  ------------------------------ | GALLERY 4 | ------------------------------  //

export default function Gallery4() {
  return (
    <section className="py-20">
      <div className="container mx-auto px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-14">
          <h2 className="text-foreground">Portfolio</h2>
          <p className="mt-4 max-w-xl mx-auto text-muted-foreground">
            At half-past eight the door opened, the policeman appeared and
            requesting them to follow him, led way to an adjoining hall.
          </p>
        </div>

        {/* Carousel */}
        <Carousel
          opts={{ align: "start", loop: true }}
          className="w-full px-12"
        >
          <CarouselContent className="-ml-4">
            {items.map((item) => (
              <CarouselItem
                key={item.id}
                className="basis-full sm:basis-1/2 lg:basis-1/3 pl-4"
              >
                <Card className="overflow-hidden mb-0">
                  <div className="aspect-video overflow-hidden">
                    <img
                      src={item.image}
                      alt={item.title}
                      className="w-full h-full object-cover"
                    />
                  </div>
                  <CardContent className="text-center">
                    <h5 className="mb-2">{item.title}</h5>
                    <p className="text-muted-foreground text-sm">
                      {item.description}
                    </p>
                  </CardContent>
                </Card>
              </CarouselItem>
            ))}
          </CarouselContent>
          <CarouselPrevious className="hidden lg:flex" />
          <CarouselNext className="hidden lg:flex" />
        </Carousel>
      </div>
    </section>
  );
}
